"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["424780"],{722243(e){e.exports=JSON.parse('{"tag":{"label":"decay","permalink":"/dst-api-webdocs/docs/tags/decay","allTagsPath":"/dst-api-webdocs/docs/tags","count":17,"items":[{"id":"game-scripts/prefabs/balloons_empty","title":"Balloons Empty","description":"A decayable container prefab that spawns mosquito sacks upon decay and water balloons when placed in inventories, with haunt mechanics that may spawn balloons.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balloons_empty"},{"id":"game-scripts/prefabs/bernie_inactive","title":"Bernie Inactive","description":"Manages the dormant state and self-decay mechanics for Bernie the Beard, including fuel consumption, reanimation logic, and equippable behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bernie_inactive"},{"id":"game-scripts/prefabs/cave_fern_withered","title":"Cave Fern Withered","description":"A withered cave fern prefab that can be harvested for cutgrass and spoils into spoiled_food after 10 seconds.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cave_fern_withered"},{"id":"game-scripts/prefabs/charlieresidue","title":"Charlieresidue","description":"A classified client-side visual effect entity that tracks a target and renders Charlie\'s residue, decaying when activated or vision conditions change.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/charlieresidue"},{"id":"game-scripts/prefabs/corpses","title":"Corpses","description":"Manages the lifecycle, mutation, looting, and decay of creature corpses, including handling lunar rift mutations and gestalt possession.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/corpses"},{"id":"game-scripts/prefabs/furtuft","title":"Furtuft","description":"A consumable/loot item that disappears over time when dropped on the ground but stops decaying when placed in an inventory slot.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/furtuft"},{"id":"game-scripts/prefabs/gelblob_storage","title":"Gelblob Storage","description":"Stores edible food items indefinitely by stopping their decay and preventing pick-up, and releases them with decay resumed upon taking.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gelblob_storage"},{"id":"game-scripts/prefabs/koalefant_carcass","title":"Koalefant Carcass","description":"Manages the state, decay, and visual progression of a koalefant carcass object, including meat consumption tracking, seasonal build variants, and decay timing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/koalefant_carcass"},{"id":"game-scripts/prefabs/mushroom_light","title":"Mushroom Light","description":"Manages the lighting, state transitions, and decay behavior of mushroom-based lanterns in DST, including battery-powered operation, spore-based colour tinting, and structural collapse when damaged.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushroom_light"},{"id":"game-scripts/prefabs/mushtree_moon","title":"Mushtree Moon","description":"Creates and configures a light-emitting, shatterable cave tree that spawns spores, drops loot when damaged, and can regrow or decay over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushtree_moon"},{"id":"game-scripts/prefabs/mushtree_spores","title":"Mushtree Spores","description":"Spore prefabs that spawn from mushtrees, persist briefly, and decay based on crowding and time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushtree_spores"},{"id":"game-scripts/prefabs/petals_evil","title":"Petals Evil","description":"A perishable, dryable, and consumable item that grants sanity loss; used as a crafting component or food source with negative effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/petals_evil"},{"id":"game-scripts/components/preservative","title":"Preservative","description":"Stores configuration for how preservation affects item decay rates, primarily used by the game\'s preservation and spoilage systems.","permalink":"/dst-api-webdocs/docs/game-scripts/components/preservative"},{"id":"game-scripts/components/preserver","title":"Preserver","description":"Controls how perish and temperature decay rates are multiplied for an entity\'s items or contents.","permalink":"/dst-api-webdocs/docs/game-scripts/components/preserver"},{"id":"game-scripts/prefabs/shallow_grave","title":"Shallow Grave","description":"Represents a buried player remains that decays over time, drops loot when hammered, and preserves player identity data for resurrection or inspection.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shallow_grave"},{"id":"game-scripts/prefabs/skeleton","title":"Skeleton","description":"Manages the creation, behavior, and decay of skeleton entities, distinguishing between generic environmental skeletons and player skeletons with avatar data and save/load persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/skeleton"},{"id":"game-scripts/prefabs/wortox_eat_soul_fx","title":"Wortox Eat Soul Fx","description":"A transient visual effect prefab that plays an eating animation when Wortox consumes a soul.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wortox_eat_soul_fx"}],"unlisted":false}}')}}]);